dashboard.definition:
{
	"dataSources": {
		"ds_KtFg8oQ2": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| search object_action = create | chart count by object_type",
				"enableSmartSources": true
			},
			"name": "Object Creation By Type - Pie chart search"
		},
		"ds_0LBHfs3r": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": " | timechart count "
			},
			"name": "Object Updates By Type - Pie chart search"
		},
		"ds_WY4obnmU": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| stats count by user"
			},
			"name": "Activity By User - Table search"
		},
		"ds_OOnwhUDc": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| stats count by appname | rename appname as app"
			},
			"name": "Activity By App - Table search"
		},
		"ds_AXgjIFgY": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| stats count by name"
			},
			"name": "Activity By Object - Table search"
		},
		"ds_sxu2HJOI": {
			"type": "ds.search",
			"options": {
				"queryParameters": {
					"earliest": "$time.earliest$",
					"latest": "$time.latest$"
				},
				"query": "| savedsearch audit_trail_knowledge_objects_query\n| search object_action IN ($ms_actions$)\n|  search object_type IN ($ms_object_types$)\n|  search name IN ($ms_object_names$)\n|  search user IN ($ms_user_names$)\n|  search appname IN ($ms_app_names$)\n|  search host IN ($ms_host_names$)\n|  search orig_body=$text_token$"
			},
			"name": "ds_baseSelection"
		},
		"ds_nQAbGEMe": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "|  eval action=object_action \n|  eval app=IF(appname=\"-missing-\",\"-\",appname)\n|  eval type=object_type\n| sort -_time,\n|  eval event=orig_body\n|  eval time=strftime(_time,\"%Y-%m-%d  %H:%M:%S.%Q\")\n|  fields time, user, action, name, event\n|  fields - _time"
			},
			"name": "Activities"
		},
		"ds_eKo8k29O_ds_WY4obnmU": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| stats count by user"
			},
			"name": "Activity By User - Chart search"
		},
		"ds_uplRMfgR_ds_OOnwhUDc": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| stats count by appname"
			},
			"name": "Activity By App - Chart search"
		},
		"ds_EkqGpKKc_ds_34ljSSqf_ds_WY4obnmU": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": " |  stats count by host"
			},
			"name": "Activity By Host - Chart search"
		},
		"ds_1dnRSxiQ_ds_KtFg8oQ2": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| search object_action = create | chart count by object_type",
