			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| stats count by name"
			},
			"name": "Activity By Object - Table search copy 1"
		},
		"ds_slbguYLS_ds_EkqGpKKc_ds_34ljSSqf_ds_WY4obnmU": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
