		"ds_SG2pKPV7_ds_slbguYLS_ds_EkqGpKKc_ds_34ljSSqf_ds_WY4obnmU": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": " |  stats count by object_type | rename object_type as type"
			},
			"name": "Activity By Type - Table search"
		},
		"ds_4IlbgBew": {
			"type": "ds.chain",
			"options": {
				"query": "| table name\n| dedup name\n| eval name=if(match(name, \".*[\\s\\(\\)].*\"), \"\\\"\" . name . \"\\\"\", name)",
				"extend": "ds_sxu2HJOI"
			},
			"name": "List of objects names"
		}
	},
