			],
			"options": {
				"columnFormat": {
					"action": {
						"data": "> table | seriesByName(\"action\") | formatByType(actionColumnFormatEditorConfig)",
						"rowColors": "> table | seriesByName(\"action\") | matchValue(actionRowColorsEditorConfig)",
